// Extract form fields from the webhook
const body = items[0].json.body || items[0].json;

const subject = body.subject || 'Unknown';
const assessmentType = body.assessment_type || 'exam';
const numQuestions = parseInt(body.num_questions) || 0;
const userId = parseInt(body.user_id) || null;
const tokenCode = body.token_code || null;
const draftOrFinal = body.draft_or_final || 'draft';
const linkedPaperId = parseInt(body.linked_paper_id) || null;
const mode = body.mode || 'A';

// Get original filename from binary data
const binaryKey = Object.keys(items[0].binary || {})[0] || 'file';
const filename = (items[0].binary && items[0].binary[binaryKey]) ? items[0].binary[binaryKey].fileName || 'upload.docx' : 'upload.docx';

return [{
  json: {
    subject,
    assessment_type: assessmentType,
    num_questions: numQuestions,
    user_id: userId,
    token_code: tokenCode,
    draft_or_final: draftOrFinal,
    linked_paper_id: linkedPaperId,
    mode: mode,
    filename,
    binaryKey
  },
  binary: items[0].binary
}];

// Parse the response from the text extraction API
const apiResponse = items[0].json;
const uploadData = $node['Parse Upload Data'].json;

const text = apiResponse.text || apiResponse.paper_text || '';
const wordCount = apiResponse.word_count || text.split(/\s+/).filter(w => w.length > 0).length;
const pageCount = apiResponse.page_count || 1;

// Escape single quotes for SQL
const safeSubject = (uploadData.subject || '').replace(/'/g, "''");
const safeAssessmentType = (uploadData.assessment_type || '').replace(/'/g, "''");
const safeFilename = (uploadData.filename || '').replace(/'/g, "''");
const safeText = text.replace(/'/g, "''");

return [{
  json: {
    user_id: uploadData.user_id,
    subject: safeSubject,
    assessment_type: safeAssessmentType,
    num_questions: uploadData.num_questions,
    filename: safeFilename,
    paper_text: safeText,
    word_count: wordCount,
    page_count: pageCount,
    token_code: uploadData.token_code,
    draft_or_final: uploadData.draft_or_final || 'draft',
    linked_paper_id: uploadData.linked_paper_id,
    mode: uploadData.mode
  }
}];

const paperId = items[0].json.id;
const tokenCode = $node['Parse Extraction'].json.token_code;
const draftOrFinal = $node['Parse Extraction'].json.draft_or_final || 'draft';

if (tokenCode) {
  const col = draftOrFinal === 'final' ? 'final_paper_id' : 'draft_paper_id';
  return [{ json: { paper_id: paperId, token_code: tokenCode, update_col: col, has_token: true } }];
}
return [{ json: { paper_id: paperId, has_token: false } }];
